 1	import React from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { DescriptionList, Title } from '@patternfly/react-core';
 5	
 6	import { ManualConnectionProps } from '../utils/types';
 7	
 8	import Detail from './Detail';
 9	
10	const ManualConnection: React.FunctionComponent<ManualConnectionProps> = ({
11	  rdp = null,
12	  spice = null,
13	  textAddress,
14	  textConnectWith,
15	  textManualConnection,
16	  textNoProtocol,
17	  textRdpAddress,
18	  textRDPPort,
19	  textSpiceAddress,
20	  textSpicePort,
21	  textSpiceTlsPort,
22	  textVNCAddress,
23	  textVNCPort,
24	  textVNCTlsPort,
25	  vnc = null,
26	}) => {
27	  const { t } = useKubevirtTranslation();
28	  const msg =
29	    spice || vnc
30	      ? textConnectWith || t('Connect with any viewer application for following protocols')
31	      : textNoProtocol || t('No connection available.');
32	  const address = spice && vnc && spice?.address === vnc?.address && spice?.address;
33	  const rdpAddress = rdp && rdp?.address !== address ? rdp?.address : null;
34	
35	  return (
36	    <div className="pf-v5-c-console__manual-connection">
37	      <Title headingLevel="h2" size="3xl">
38	        {textManualConnection || t('Manual Connection')}
39	      </Title>
40	      <p>{msg}</p>
41	      <DescriptionList className="pf-v6-c-description-list">
42	        {address && <Detail title={textAddress || t('Address')} value={address} />}
43	        {!address && spice && (
44	          <Detail title={textSpiceAddress || t('SPICE Address')} value={spice?.address} />
45	        )}
46	        {rdpAddress && <Detail title={textRdpAddress || t('RDP Address')} value={rdpAddress} />}
47	        {spice?.port && <Detail title={textSpicePort || t('SPICE Port')} value={spice?.port} />}
48	        {spice?.tlsPort && (
49	          <Detail title={textSpiceTlsPort || t('SPICE TLS Port')} value={spice?.tlsPort} />
50	        )}
51	        {!address && vnc && (
52	          <Detail title={textVNCAddress || t('VNC Address')} value={vnc?.address} />
53	        )}
54	        {vnc?.port && <Detail title={textVNCPort || t('VNC Port')} value={vnc?.port} />}
55	        {vnc?.tlsPort && (
56	          <Detail title={textVNCTlsPort || t('VNC TLS Port')} value={vnc?.tlsPort} />
57	        )}
58	        {rdp?.port && <Detail title={textRDPPort || t('RDP Port')} value={rdp?.port} />}
59	      </DescriptionList>
60	    </div>
61	  );
62	};
63	
64	export default ManualConnection;

